parameters.jsCode:
const agentResponse = $input.first().json;

try {
  // Cortex Agentのレスポンスをパース
  let content = agentResponse.choices?.[0]?.message?.content || agentResponse.content || agentResponse;

  // 文字列の場合はJSONパース
  if (typeof content === 'string') {
    // JSONブロックを抽出（```json ... ``` の形式に対応）
    const jsonMatch = content.match(/```json\s*([\s\S]*?)```/) || content.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      content = JSON.parse(jsonMatch[1] || jsonMatch[0]);
    } else {
      content = JSON.parse(content);
    }
  }

  return [{
    json: {
      can_resolve: content.can_resolve ?? false,
      confidence: content.confidence ?? 0,
      matched_kb_id: content.matched_kb_id || null,
      response: content.response || 'エラーが発生しました',
      resolution_steps: content.resolution_steps || [],
      needs_escalation: content.needs_escalation ?? true,
      escalation_reason: content.escalation_reason || '',
      escalation_team: content.escalation_team || 'GENERAL_SUPPORT',
      // 元のSlackメッセージ情報を保持
      original_text: $('Webhook').first().json.text,
      user_name: $('Webhook').first().json.user_name,
      user_id: $('Webhook').first().json.user_id,
      channel: $('Webhook').first().json.channel,
      ts: $('Webhook').first().json.ts
    }
  }];
} catch (e) {
  // パース失敗時
  return [{
    json: {
      can_resolve: false,
      confidence: 0,
      matched_kb_id: null,
      response: 'AI解析に失敗しました',
      resolution_steps: [],
      needs_escalation: true,
      escalation_reason: 'AI解析エラー: ' + e.message,
      escalation_team: 'GENERAL_SUPPORT',
      original_text: $('Webhook').first().json.text,
      user_name: $('Webhook').first().json.user_name,
      user_id: $('Webhook').first().json.user_id,
      channel: $('Webhook').first().json.channel,
      ts: $('Webhook').first().json.ts
    }
  }];
}

